mapper.select:
SELECT offering_id, member_id, member_name, amount, offering_type, offering_date, description, input_by, reg_date FROM erp_offering
AND (member_name LIKE '%' || #{keyword} || '%' OR offering_type LIKE '%' || #{keyword} || '%')
ORDER BY offering_date DESC LIMIT #{limit} OFFSET #{offset}

SELECT offering_id, member_id, member_name, amount, offering_type, offering_date, description, input_by, reg_date FROM erp_offering
AND member_name LIKE '%' || #{keyword} || '%'
ORDER BY reg_date DESC LIMIT #{limit} OFFSET #{offset}

SELECT budget_id, budget_year, category, planned_amount, description, status
FROM erp_budget

    AND budget_year = #{year}

ORDER BY budget_year DESC, category
LIMIT #{limit} OFFSET #{offset}

SELECT expense_id, expense_date, category, amount, description, approved_by, reg_date FROM erp_expense
AND (category LIKE '%' || #{keyword} || '%' OR description LIKE '%' || #{keyword} || '%')
ORDER BY expense_date DESC LIMIT #{limit} OFFSET #{offset}

SELECT
    COALESCE((SELECT SUM(amount) FROM erp_offering
              WHERE TO_CHAR(offering_date, 'YYYY') = #{year}
              AND TO_CHAR(offering_date, 'MM') = #{month}
             ), 0) AS income,
    COALESCE((SELECT SUM(amount) FROM erp_expense
              WHERE TO_CHAR(expense_date, 'YYYY') = #{year}
              AND TO_CHAR(expense_date, 'MM') = #{month}
             ), 0) AS expense,
    COALESCE((SELECT SUM(amount) FROM erp_offering
              WHERE TO_CHAR(offering_date, 'YYYY') = #{year}
              AND TO_CHAR(offering_date, 'MM') = #{month}
             ), 0)
    - COALESCE((SELECT SUM(amount) FROM erp_expense
                WHERE TO_CHAR(expense_date, 'YYYY') = #{year}
                AND TO_CHAR(expense_date, 'MM') = #{month}
               ), 0) AS balance

SELECT offering_id, member_id, member_name, amount, offering_type,
       offering_date, description, input_by, reg_date
FROM erp_offering
WHERE TO_CHAR(offering_date, 'YYYY') = #{year}
AND TO_CHAR(offering_date, 'MM') = #{month}
ORDER BY offering_date DESC
